        // === Avatar editing (MVU write-back) ===
        const __statusmenu_state = { gameData: null, stat: null, currentKinKey: null };

        function openPortraitModeModal(evt, kinKey) {
            try {
                if (evt) { evt.preventDefault(); evt.stopPropagation(); }
                __statusmenu_state.currentKinKey = kinKey;
                const modal = document.getElementById('portrait-mode-modal');
                if (modal) modal.style.display = 'flex';
            } catch (e) { console.error('openPortraitModeModal error:', e); }
        }

        function closePortraitModeModal() {
            const modal = document.getElementById('portrait-mode-modal');
            if (modal) modal.style.display = 'none';
            __statusmenu_state.currentKinKey = null;
        }

        function normalizePortraitUrl(raw) {
            const trimmed = String(raw ?? '').trim();
            if (!trimmed) return '';
            if (!/^https?:\/\//i.test(trimmed)) return '';
            return trimmed;
        }

        async function saveStatData(updatedStat) {
            if (!updatedStat) return;
            const messageId = (typeof getCurrentMessageId === 'function') ? getCurrentMessageId() : 'last';

            try {
                // Priority: MVU Extension (updateVariablesWith)
                if (typeof updateVariablesWith === 'function') {
                    await updateVariablesWith((vars) => {
                        if (typeof _ !== 'undefined' && _.set) {
                            _.set(vars, 'stat_data', updatedStat);
                        } else {
                            vars.stat_data = updatedStat;
                        }
                        return vars;
                    }, { type: 'message', message_id: messageId });
                }
                // Fallback: Standard SillyTavern API
                else if (typeof window.insertOrAssignVariables === 'function') {
                    const payload = { stat_data: updatedStat };
                    await window.insertOrAssignVariables(payload, { type: 'chat' });
                    await window.insertOrAssignVariables(payload, { type: 'message', message_id: messageId });
                } else {
                    alert(LOCALE.alert_no_func);
                    return;
                }

                __statusmenu_state.stat = updatedStat;
                if (__statusmenu_state.gameData) __statusmenu_state.gameData.stat_data = updatedStat;
                renderKinList('kin-container', updatedStat.Familiar || {});

            } catch (e) {
                console.error('saveStatData failed:', e);
                alert(LOCALE.alert_save_fail);
            }
        }

        async function applyPortraitUpdate(mode, rawInput) {
            const kinKey = __statusmenu_state.currentKinKey;
            if (!kinKey) return;
            const url = normalizePortraitUrl(rawInput);
            if (!url) { alert(LOCALE.alert_invalid_url); return; }
            const stat = __statusmenu_state.stat;
            if (!stat) { alert(LOCALE.alert_no_stat); return; }

            if (kinKey === '__MAINCHAR__') {
                // Handle Main Character
                stat.Mainchar = stat.Mainchar || {};
                const existing = stat.Mainchar.Image;
                const label = (Array.isArray(existing) && existing.length > 1) ? existing[1] : 'Portrait';
                stat.Mainchar.Image = [url, label];
            } else {
                stat.Familiar = stat.Familiar || {};
                stat.Familiar[kinKey] = stat.Familiar[kinKey] || {};
                const existing = stat.Familiar[kinKey].Image;
                const label = (Array.isArray(existing) && existing.length > 1) ? existing[1] : 'Avatar';
                stat.Familiar[kinKey].Image = [url, label];
            }

            await saveStatData(stat);
            closePortraitModeModal();
        }

        async function toggleKinBattleTeam(evt, kinKey, checked) {
            try {
                if (evt) { evt.preventDefault(); evt.stopPropagation(); }
                const stat = __statusmenu_state.stat;
                if (!stat || !kinKey) return;
                stat.Familiar = stat.Familiar || {};
                stat.Familiar[kinKey] = stat.Familiar[kinKey] || {};
                const existing = stat.Familiar[kinKey].Is_in_battle_team;
                const label = (Array.isArray(existing) && existing.length > 1) ? existing[1] : LOCALE.lbl_kin_in_team;
                stat.Familiar[kinKey].Is_in_battle_team = [!!checked, label];
                await saveStatData(stat);
            } catch (e) {
                console.error('toggleKinBattleTeam failed:', e);
                alert(LOCALE.alert_save_fail);
            }
        }

        // === 主更新邏輯 ===
        async function updateStatusPanel(gameData) {
            if (!gameData || !gameData.stat_data) return;
            const stat = gameData.stat_data;

            __statusmenu_state.gameData = gameData;
            __statusmenu_state.stat = stat;

            // ---- World (label comes from tuple[1]) ----
            setKV('lbl-world-date', 'world-date', stat, 'World.Date', 'Date');
            setKV('lbl-world-time', 'world-time', stat, 'World.Time', 'Time');
            setKV('lbl-world-location', 'world-location', stat, 'World.Location', 'Location');
            setKV('lbl-world-webther', 'world-weather', stat, 'World.Weather', 'Weather');

            // ---- Main Character Avatar ----
            const mcImg = document.getElementById('mc-avatar-img');
            if (mcImg) {
                const rawImg = getV(stat, 'Mainchar.Image');
                mcImg.src = (rawImg && rawImg !== "N/A") ? rawImg : "";
                mcImg.style.display = (rawImg && rawImg !== "N/A") ? 'block' : 'none';
            }
            setText('mc-name-display', getV(stat, 'Mainchar.Name', ''));

            // ---- Main Character Vitals ----
            // Labels for the vitals bar (read from tuple[1])
            setText('lbl-vital-hp', getL(stat, 'Mainchar.Hp_curr', 'HP'));
            setText('lbl-vital-mp', getL(stat, 'Mainchar.Mp_curr', 'MP'));
            setText('lbl-vital-sta', getL(stat, 'Mainchar.Sta_curr', 'Stamina'));

            const hp_max = Number(getV(stat, 'Mainchar.Hp_max', 100)) || 100;
            const hp_cur = Math.min(Number(getV(stat, 'Mainchar.Hp_curr', 0)) || 0, hp_max);
            updateProgressBar('hp-bar', 'hp-value', hp_cur, hp_max);

            const mp_max = Number(getV(stat, 'Mainchar.Mp_max', 100)) || 100;
            const mp_cur = Math.min(Number(getV(stat, 'Mainchar.Mp_curr', 0)) || 0, mp_max);
            updateProgressBar('mp-bar', 'mp-value', mp_cur, mp_max);

            const sta_max = Number(getV(stat, 'Mainchar.Sta_max', 100)) || 100;
            const sta_cur = Math.min(Number(getV(stat, 'Mainchar.Sta_curr', 0)) || 0, sta_max);
            updateProgressBar('sta-bar', 'sta-value', sta_cur, sta_max);

            // ---- Core (labels from tuples) ----
            setKV('lbl-core-name', 'core-name', stat, 'Mainchar.Name', 'Name');
            setKV('lbl-core-race', 'core-race', stat, 'Mainchar.Race', 'Race');
            setKV('lbl-core-occupation', 'core-occupation', stat, 'Mainchar.Occupation', 'Occupation');
            setKV('lbl-core-level', 'core-level', stat, 'Mainchar.Level', 'Level');
            setKV('lbl-core-exp', 'core-exp', stat, 'Mainchar.Exp', 'Exp');
            setKV('lbl-core-mental', 'core-mental', stat, 'Mainchar.Mental_state', 'Mental');
            setKV('lbl-core-points', 'core-points', stat, 'Mainchar.Core-points', 'Points');

            // ---- Attributes ----
            setKV('lbl-attr-strength', 'attr-strength', stat, 'Mainchar.Strength', 'Strength');
            setKV('lbl-attr-agility', 'attr-agility', stat, 'Mainchar.Agility', 'Agility');
            setKV('lbl-attr-constitution', 'attr-constitution', stat, 'Mainchar.Constitution', 'Constitution');
            setKV('lbl-attr-intelligence', 'attr-intelligence', stat, 'Mainchar.Intelligence', 'Intelligence');
            setKV('lbl-attr-wisdom', 'attr-wisdom', stat, 'Mainchar.Wisdom', 'Wisdom');
            setKV('lbl-attr-charisma', 'attr-charisma', stat, 'Mainchar.Charisma', 'Charisma');

            // ---- Derived combat stats ----
            setKV('lbl-der-p-dmg', 'der-p-dmg', stat, 'Mainchar.Physical_attack', 'P.Atk');
            setKV('lbl-der-p-def', 'der-p-def', stat, 'Mainchar.Physical_defense', 'P.Def');
            setKV('lbl-der-m-dmg', 'der-m-dmg', stat, 'Mainchar.Magic_attack', 'M.Atk');
            setKV('lbl-der-m-def', 'der-m-def', stat, 'Mainchar.Magic_defense', 'M.Def');
            setKV('lbl-der-m-assist', 'der-m-assist', stat, 'Mainchar.Magic_assist', 'M.Ast');

            // ---- Lists / grids (tuple-safe renderers) ----
            renderQuestList('quest-list', getAt(stat, 'Mainchar.Quests', {}), LOCALE.empty_quest);
            renderGridList('skills-list', getAt(stat, 'Mainchar.Skills', {}), LOCALE.empty_skills);
            renderSimpleList('equipped-items-list', getAt(stat, 'Mainchar.Equipment', {}), LOCALE.empty_equipped);
            renderGridList('inventory-list', getAt(stat, 'Mainchar.Inventory', {}), LOCALE.empty_inventory);
            renderSimpleList('talents-list', getAt(stat, 'Mainchar.Talents', {}), LOCALE.empty_talents);
            renderSimpleList('companions-list', getAt(stat, 'Mainchar.Companions', {}), LOCALE.empty_companions);
            renderSimpleList('real-estate-list', getAt(stat, 'Mainchar.Real_estate', {}), LOCALE.empty_real_estate);
            renderSimpleList('buffs-list', getAt(stat, 'Mainchar.Buffs', {}), LOCALE.empty_buffs);
            renderSimpleList('ailments-list', getAt(stat, 'Mainchar.Ailments', {}));
            renderSimpleList('mods-list', getAt(stat, 'Mainchar.Mods', {}), LOCALE.empty_mods);

            renderKinList('kin-container', getAt(stat, 'Familiar', {}));

            // ---- Map Logic ----
            const mcLevel = Number(getV(stat, 'Mainchar.Level', 0)) || 0;
            const mapContainer = document.getElementById('map-container');

            if (mapContainer) {
                let mapUrl = '';
                const mapWiKey = mcLevel < 71 ? 'pre-70-map' : 'post-70-map';

                try {
                    // API Discovery: Check Global (Script Runner) then Parent (ST Window)
                    const _getPrimaryBook = (typeof getCurrentCharPrimaryLorebook === 'function')
                        ? getCurrentCharPrimaryLorebook
                        : (typeof window.parent !== 'undefined' && window.parent.getCurrentCharPrimaryLorebook);

                    const _getEntries = (typeof getLorebookEntries === 'function')
                        ? getLorebookEntries
                        : (typeof window.parent !== 'undefined' && window.parent.getLorebookEntries);

                    if (typeof _getPrimaryBook === 'function' && typeof _getEntries === 'function') {
                        const bookName = await _getPrimaryBook();
                        if (bookName) {
                            const entries = await _getEntries(bookName);
                            if (Array.isArray(entries)) {
                                // Search: Check 'keys' array, legacy 'key', or 'comment' field.
                                // Case-insensitive matching.
                                const entry = entries.find(e => {
                                    const keys = e.keys || e.key;
                                    const hasKey = Array.isArray(keys) && keys.some(k => k.trim().toLowerCase() === mapWiKey.toLowerCase());
                                    const hasComment = e.comment && e.comment.trim().toLowerCase() === mapWiKey.toLowerCase();
                                    return hasKey || hasComment;
                                });

                                if (entry) {
                                    mapUrl = entry.content;
                                }
                            }
                        }
                    }


                } catch (e) {
                    console.error("Error fetching map:", e);
                }

                if (mapUrl && typeof mapUrl === 'string') {
                    const trimmed = mapUrl.trim();
                    if (trimmed && /^https?:\/\//i.test(trimmed)) {
                        mapContainer.innerHTML = `<img src="${trimmed}" style="width:100%; height:auto; object-fit:contain; border-radius:4px; box-shadow:0 0 5px rgba(0,0,0,0.5);" alt="Map" onclick="showImageModal('Map', '${trimmed}')" style="cursor:pointer">`;
                        if (mapContainer.querySelector('img')) mapContainer.querySelector('img').style.cursor = 'pointer';
                    } else {
                        mapContainer.innerHTML = `<span style="font-size:0.8em; color:var(--text-secondary);">(Invalid URL)</span>`;
                    }
                } else {
                    mapContainer.innerHTML = `<div style="display:flex; flex-direction:column; gap:5px;">
                        <span style="font-size:0.8em; color:var(--text-secondary);">(No Map Data)</span>
                     </div>`;
                }
            }
        }




        async function applyLocalization() {
            // Tabs
            setText('btn-tab-overview', LOCALE.tab_overview);
            setText('btn-tab-attributes', LOCALE.tab_attributes);
            setText('btn-tab-kin', LOCALE.tab_kin);
            setText('btn-tab-equipment', LOCALE.tab_equipment);
            setText('btn-tab-inventory', LOCALE.tab_inventory);
            setText('btn-tab-social', LOCALE.tab_social);

            // Headers
            setText('header-world', LOCALE.header_world);
            setText('header-core', LOCALE.header_core);
            setText('header-quest', LOCALE.header_quest);
            setText('header-vitals', LOCALE.header_vitals);
            setText('header-combat', LOCALE.header_combat);
            setText('header-skills', LOCALE.header_skills);
            setText('header-equipped', LOCALE.header_equipped);
            setText('header-inventory', LOCALE.header_inventory);
            setText('header-talents', LOCALE.header_talents);
            setText('header-real-estate', LOCALE.header_real_estate);
            setText('header-status-assist', LOCALE.header_status_assist);
            setText('header-map', (LOCALE.header_map) ? LOCALE.header_map : "Location Map");

            // Modal UI
            setText('ui-modal-title', LOCALE.ui_select_portrait);
            setText('ui-btn-url', LOCALE.ui_url_btn);
            setText('ui-help-url', LOCALE.ui_url_help);
            setText('ui-hint-url', LOCALE.ui_url_hint);
        }

        document.addEventListener('DOMContentLoaded', async () => {
            await applyLocalization();
            try {
                const closeBtn = document.getElementById('portrait-mode-close-btn');
                if (closeBtn) closeBtn.addEventListener('click', closePortraitModeModal);
                const modal = document.getElementById('portrait-mode-modal');
                if (modal) {
                    modal.addEventListener('click', (e) => { if (e.target === modal) closePortraitModeModal(); });
                    modal.querySelectorAll('[data-portrait-mode]').forEach(btn => {
                        btn.addEventListener('click', (e) => {
                            e.preventDefault(); e.stopPropagation();
                            const raw = prompt(LOCALE.ui_prompt_url, '');
                            if (raw === null) return;
                            applyPortraitUpdate('url', raw);
                        });
                    });
                }
                const messages = await getChatMessages(getCurrentMessageId());
                const gameData = messages.length > 0 ? messages[0].data : {};
                await updateStatusPanel(gameData);
            } catch (error) { console.error(error); }
        });

        // MVU polling refresh (no events) + redraw only on change
        let _lastStatData = null;

        const refreshFromMvu = async () => {
            const modal = document.getElementById("portrait-mode-modal");
            if (modal && modal.style.display === "flex") return false;
            let latestStatData = null;

            // 1. Try to get data from variables (Live State)
            const targetWindow = (typeof window.getVariables === "function" && window) || (window.parent && typeof window.parent.getVariables === "function" && window.parent) || null;

            if (targetWindow) {
                const msgId = (typeof getCurrentMessageId === "function") ? getCurrentMessageId() : -1;
                const context = { type: 'message', message_id: msgId };

                // Try to get variables with context (matches testsample.html behavior)
                const vars = targetWindow.getVariables(context);
                if (vars && vars.stat_data) {
                    latestStatData = vars.stat_data;
                }
                // Fallback: Try without context
                else {
                    const globalVars = targetWindow.getVariables();
                    if (globalVars && globalVars.stat_data) {
                        latestStatData = globalVars.stat_data;
                    }
                }
            }

            // 2. Fallback: Try to get data from the specific chat message (Persisted State)
            if (!latestStatData && typeof getCurrentMessageId === "function") {
                const msgId = getCurrentMessageId();
                if (msgId) {
                    try {
                        const messages = await getChatMessages(msgId);
                        const msgStat = messages?.[0]?.data?.stat_data;
                        if (msgStat) latestStatData = msgStat;
                    } catch (e) { console.warn("getChatMessages failed", e); }
                }
            }

            // Change Detection & Update to avoid redraw
            if (latestStatData) {
                // Use Lodash isEqual if available, otherwise simple JSON stringify
                const isDifferent = (typeof _ !== 'undefined' && _.isEqual)
                    ? !_lastStatData || !_.isEqual(latestStatData, _lastStatData)
                    : JSON.stringify(latestStatData) !== JSON.stringify(_lastStatData);

                if (isDifferent) {
                    console.log("Data changed, refreshing UI...", { old: _lastStatData, new: latestStatData });
                    await updateStatusPanel({ stat_data: latestStatData });

                    // Clone data for next comparison to avoid reference issues
                    if (typeof _ !== 'undefined' && _.cloneDeep) {
                        _lastStatData = _.cloneDeep(latestStatData);
                    } else {
                        _lastStatData = JSON.parse(JSON.stringify(latestStatData));
                    }
                    return true;
                }
            } else {
                console.log("MVU Debug: No data found");
            }
            return false;
        };
        refreshFromMvu().catch(() => { });
        setInterval(() => { refreshFromMvu().catch(() => { }); }, 2000);
    </script>
