        { path: `${derivedPath}魔力值.當前值`, min: 0, max: maxMP },
        { path: `${derivedPath}精力.當前值`, min: 0, max: maxStamina },
    ];

    for (const config of clampConfigs) {
        const value = _.get(variables, config.path);
        if (typeof value === 'number') {
